A debounce function delays the execution of a callback until a specified time has passed since the last invocation, preventing excessive calls (e.g., during rapid user input like typing).

```javascript
function debounce(func, delay) {
  let timeoutId;
  return function (...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(this, args), delay);
  };
}

// Example usage: Debouncing a search input handler
const searchInput = document.getElementById('search');
const debouncedSearch = debounce((query) => {
  console.log('Searching for:', query); // This runs after 300ms of no typing
}, 300);

searchInput.addEventListener('input', (e) => {
  debouncedSearch(e.target.value);
});
```
